<?php $__env->startSection('title','Cart'); ?>
<?php $__env->startSection('content'); ?><div class="container py-5"><h1>Cart</h1><div class="table-card"><table class="table align-middle"><thead><tr><th>Product</th><th>Price</th><th width="160">Quantity</th><th>Total</th><th></th></tr></thead><tbody><?php ($subtotal=0); ?><?php $__empty_1 = true; $__currentLoopData = $cart->items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><?php ($line=$item->quantity*$item->product->selling_price); ?><?php ($subtotal+=$line); ?><tr><td><?php echo e($item->product->name); ?></td><td>৳<?php echo e(number_format($item->product->selling_price,2)); ?></td><td><form method="post" action="<?php echo e(route('cart.update',$item)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('PUT'); ?><input class="form-control" name="quantity" type="number" min="1" value="<?php echo e($item->quantity); ?>" onchange="this.form.submit()"></form></td><td>৳<?php echo e(number_format($line,2)); ?></td><td><form method="post" action="<?php echo e(route('cart.destroy',$item)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('DELETE'); ?><button class="btn btn-sm btn-outline-danger">Remove</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="5" class="text-center text-muted">Your cart is empty.</td></tr><?php endif; ?></tbody></table><div class="d-flex justify-content-between align-items-center"><strong>Subtotal: ৳<?php echo e(number_format($subtotal,2)); ?></strong><a class="btn btn-primary" href="<?php echo e(route('checkout.create')); ?>">Checkout</a></div></div></div><?php $__env->stopSection(); ?>

